using Contoso.Pricing;

namespace Contoso.Pricing.Tests;

[TestClass]
public sealed class PriceCalculatorTests
{
    private PriceCalculator _calculator = null!;

    [TestInitialize]
    public void Setup() => _calculator = new PriceCalculator();

    // ──────────────────────────────────────────────
    //  CalculateTotal – DataRow tests
    // ──────────────────────────────────────────────

    [TestMethod]
    [DataRow(10.00, 1, 0.0,  10.00,  DisplayName = "Single item, no tax")]
    [DataRow(10.00, 5, 0.0,  50.00,  DisplayName = "Multiple items, no tax")]
    [DataRow(10.00, 1, 0.10, 11.00,  DisplayName = "Single item, 10% tax")]
    [DataRow(25.50, 3, 0.08, 82.62,  DisplayName = "Fractional price, 8% tax")]
    [DataRow(0.00,  5, 0.10, 0.00,   DisplayName = "Zero price yields zero total")]
    [DataRow(10.00, 0, 0.10, 0.00,   DisplayName = "Zero quantity yields zero total")]
    [DataRow(99.99, 1, 1.0,  199.98, DisplayName = "Maximum tax rate (100%)")]
    public void CalculateTotal_WithValidInputs_ReturnsExpectedTotal(
        double unitPrice, int quantity, double taxRate, double expectedTotal)
    {
        var result = _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate);

        Assert.AreEqual((decimal)expectedTotal, result);
    }

    // ──────────────────────────────────────────────
    //  CalculateTotal – invalid-input DataRow tests
    // ──────────────────────────────────────────────

    [TestMethod]
    [DataRow(-1.00, 1,  0.10, DisplayName = "Negative unit price throws")]
    public void CalculateTotal_NegativeUnitPrice_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, -1, 0.10, DisplayName = "Negative quantity throws")]
    public void CalculateTotal_NegativeQuantity_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    [TestMethod]
    [DataRow(10.00, 1, -0.01, DisplayName = "Tax rate below 0 throws")]
    [DataRow(10.00, 1,  1.01, DisplayName = "Tax rate above 1 throws")]
    public void CalculateTotal_InvalidTaxRate_Throws(
        double unitPrice, int quantity, double taxRate)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.CalculateTotal((decimal)unitPrice, quantity, (decimal)taxRate));
    }

    // ──────────────────────────────────────────────
    //  ApplyDiscount – DynamicData tests
    // ──────────────────────────────────────────────

    public static IEnumerable<object[]> ApplyDiscountCases
    {
        get
        {
            yield return new object[] { 100.00m, 0.00m,   100.00m, "No discount" };
            yield return new object[] { 100.00m, 10.00m,  90.00m,  "10% discount" };
            yield return new object[] { 100.00m, 50.00m,  50.00m,  "50% discount" };
            yield return new object[] { 100.00m, 100.00m, 0.00m,   "100% discount (free)" };
            yield return new object[] { 49.99m,  25.00m,  37.4925m,"Fractional result" };
            yield return new object[] { 0.00m,   50.00m,  0.00m,   "Zero price stays zero" };
        }
    }

    [TestMethod]
    [DynamicData(nameof(ApplyDiscountCases))]
    public void ApplyDiscount_WithValidInputs_ReturnsExpectedPrice(
        decimal price, decimal discountPercent, decimal expected, string scenario)
    {
        var result = _calculator.ApplyDiscount(price, discountPercent);

        Assert.AreEqual(expected, result, $"Failed for scenario: {scenario}");
    }

    // ──────────────────────────────────────────────
    //  ApplyDiscount – boundary / error DynamicData
    // ──────────────────────────────────────────────

    public static IEnumerable<object[]> InvalidDiscountCases
    {
        get
        {
            yield return new object[] { 100.00m, -1.00m,  "Negative discount" };
            yield return new object[] { 100.00m, 100.01m, "Discount exceeds 100%" };
        }
    }

    [TestMethod]
    [DynamicData(nameof(InvalidDiscountCases))]
    public void ApplyDiscount_InvalidDiscount_Throws(
        decimal price, decimal discountPercent, string scenario)
    {
        Assert.ThrowsException<ArgumentOutOfRangeException>(
            () => _calculator.ApplyDiscount(price, discountPercent),
            $"Expected exception for scenario: {scenario}");
    }

    // ──────────────────────────────────────────────
    //  FormatPrice – DataRow tests
    // ──────────────────────────────────────────────

    [TestMethod]
    [DataRow(19.99,  "$",  "$19.99",  DisplayName = "Default USD symbol")]
    [DataRow(19.99,  "€",  "€19.99",  DisplayName = "Euro symbol")]
    [DataRow(1000.5, "$",  "$1000.50", DisplayName = "Pads to two decimals")]
    [DataRow(0.00,   "£",  "£0.00",   DisplayName = "Zero with pound sign")]
    public void FormatPrice_ReturnsCorrectlyFormattedString(
        double price, string symbol, string expected)
    {
        var result = _calculator.FormatPrice((decimal)price, symbol);

        Assert.AreEqual(expected, result);
    }
}

